// ScanConvesion for curved Probe, mex file to use with look up table generated by ScanConverterTable3.m in matlab

#include "math.h"
#include "mex.h"

void ScanConvert(float * LUT_coeff,short * LUT_X, short * LUT_Z ,short * LUT_Vois1, short * LUT_Vois2 ,int NbVois,int LUTSIZE,int Nx,int Ntheta, float * DataOriginal,float * DataFinal)
{
    
    int k,n ;
    int x,y ;
    
    int NbVoisTot = (2*NbVois) ;
    int SeekOffSet = 0 ;
    
    float Data = 0 ;
    short * Vois1 ;
    short * Vois2 ;
    
    //float * coeff ;
    //float * value ;
    
    NbVoisTot*= NbVoisTot ;
    mexPrintf("NbVoisTot = %d\n",NbVoisTot);
    mexPrintf("LUTSIZE = %d\n",LUTSIZE);

    //coeff = (float*)malloc(sizeof(float)*NbVoisTot);
    //value = (float*)malloc(sizeof(float)*NbVoisTot);
   
    for(k=0;k<LUTSIZE;k++)
    {
        
        SeekOffSet = k*NbVoisTot ;
        
        Vois1 = LUT_Vois1 + SeekOffSet;
        Vois2 = LUT_Vois2 + SeekOffSet;
        
        /*
        for(n=0;n<NbVoisTot;n++)
        {
            coeff[n] = LUT_coeff[n + SeekOffSet] ;
            value[n] = DataOriginal[Vois1[n]+Ntheta*Vois2[n]];
        }
                      
        x = (int)LUT_X[k];
        y = (int)LUT_Z[k];
               
        Data = coeff[0]*value[0];
       
        for(n=1;n<NbVoisTot;n++)
        {        
            Data += coeff[n]*value[n];
        }*/
        
        Data = 0;
        for(n=0;n<NbVoisTot;n++)
        {
            float a = LUT_coeff[n + SeekOffSet] ;
            float b = DataOriginal[Vois1[n]+Ntheta*Vois2[n]];
            Data += a*b;  
        }
                      
        x = (int)LUT_X[k];
        y = (int)LUT_Z[k];
        
       DataFinal[x+Nx*y] = (Data) ;
    }
    //DataFinal[0] = Data ;

    //free(coeff);
    //free(value);
}
