void mexFunction(int nlhs, mxArray *plhs[],int nrhs, const mxArray *prhs[])
{    
    
    float * LUT_coeff ;
    short * LUT_X, * LUT_Z ;
    short * LUT_Vois1, * LUT_Vois2 ;
    
    float * DataOriginal ;
    float * DataFinal ;
    
    int NbVois ;
    int LUTSIZE ;
    
    int Nx, Ntheta ;
    
    LUT_coeff = (float*)mxGetPr(prhs[0]);
    LUT_X = (short*)mxGetPr(prhs[1]);
    LUT_Z = (short*)mxGetPr(prhs[2]);
    LUT_Vois1 = (short*)mxGetPr(prhs[3]);
    LUT_Vois2 = (short*)mxGetPr(prhs[4]);
    NbVois = (int)(*(double*)mxGetPr(prhs[5]));
    LUTSIZE = (int)(*(int*)mxGetPr(prhs[6]));
    DataOriginal = (float*)mxGetPr(prhs[7]);
    DataFinal = (float*)mxGetPr(prhs[8]);
    
    Nx = mxGetM(prhs[8]); // Get the number of column in DataFinal
    Ntheta = mxGetM(prhs[7]); // Get the number of column in DataOriginal
    mexPrintf("Ne = %d\n",Nx);
    ScanConvert(LUT_coeff,LUT_X,LUT_Z,LUT_Vois1,LUT_Vois2,NbVois,LUTSIZE,Nx,Ntheta,DataOriginal,DataFinal); // Call scanconvert
       
}

